// Nodo: "Process Calendar" - VERSIÓN CORREGIDA
const inputData = $input.all()[0].json;

let rawText = "";

console.log("📅 Datos recibidos:", Object.keys(inputData));

// Extraer el texto de la respuesta de Jina Reader
// Jina devuelve un objeto con { data: "contenido en markdown" }
if (inputData.data && typeof inputData.data === 'string') {
    rawText = inputData.data;
    console.log(`✅ Texto extraído de 'data': ${rawText.length} caracteres`);
} 
// Si es string directamente
else if (typeof inputData === 'string') {
    rawText = inputData;
    console.log(`✅ Texto extraído de string: ${rawText.length} caracteres`);
}
// Si hay raw_text
else if (inputData.raw_text) {
    rawText = inputData.raw_text;
    console.log(`✅ Texto extraído de raw_text: ${rawText.length} caracteres`);
}
// Si hay text
else if (inputData.text) {
    rawText = inputData.text;
    console.log(`✅ Texto extraído de text: ${rawText.length} caracteres`);
}

// Limpiar caracteres de escape
rawText = rawText.replace(/\\n/g, '\n').replace(/\\"/g, '"').replace(/\\\\/g, '\\');

console.log(`📄 Primeros 300 caracteres: ${rawText.substring(0, 300)}`);

// ============================================
// EXTRAER EVENTOS DEL CALENDARIO
// ============================================

let events = [];
const lines = rawText.split('\n');

// Buscar eventos para todas las divisas relevantes
const allCurrencies = ["EUR", "USD", "GBP", "JPY", "CHF", "CAD", "AUD", "NZD"];

for (let i = 0; i < lines.length; i++) {
    const line = lines[i];

    for (const currency of allCurrencies) {
        if (line.includes(`| ${currency} |`) || line.includes(` ${currency} |`)) {
            const cells = line.split('|').map(c => c.trim());
            let event = "";
            let impact = "low";
            let actual = "", forecast = "", previous = "";

            for (const cell of cells) {
                if (cell.includes('ff-impact-red')) impact = "high";
                else if (cell.includes('ff-impact-ora')) impact = "medium";

                if (cell.length > 4 && cell.match(/[A-Za-z]/) && !cell.match(/^\d{1,2}:\d{2}/)) {
                    if (!cell.includes('Image') && !cell.includes('Graph') && !cell.includes('Open Detail')) {
                        event = cell;
                    }
                }

                if (cell.match(/^-?\d+\.?\d*%?$/) || cell.match(/^-?\d+[KMB]?$/)) {
                    if (!actual) actual = cell;
                    else if (!forecast) forecast = cell;
                    else if (!previous) previous = cell;
                }
            }

            if (event && event.length > 3 && !event.includes('Alerts') && !event.includes('Detail')) {
                events.push({
                    currency: currency,
                    event: event,
                    impact: impact,
                    actual: actual || null,
                    forecast: forecast || null,
                    previous: previous || null
                });
            }
        }
    }
}

// Eliminar duplicados
const uniqueEvents = [];
const eventKeys = new Set();
for (const event of events) {
    const key = `${event.currency}_${event.event}`;
    if (!eventKeys.has(key)) {
        eventKeys.add(key);
        uniqueEvents.push(event);
    }
}

// Ordenar por impacto
uniqueEvents.sort((a, b) => {
    const order = { high: 0, medium: 1, low: 2 };
    return (order[a.impact] || 3) - (order[b.impact] || 3);
});

const topEvents = uniqueEvents.slice(0, 12);

console.log(`📅 ${topEvents.length} eventos procesados`);
topEvents.forEach(e => console.log(`   - ${e.currency}: ${e.event} (${e.impact})`));

return [{
    json: {
        calendar: topEvents,
        calendar_count: topEvents.length,
        high_impact_count: topEvents.filter(e => e.impact === "high").length
    }
}];
